using System.Net;

var builder = WebApplication.CreateBuilder(args);

// BREAKING CHANGE (.NET 9): ValidateScopes is now enabled by default in
// development. A Singleton must not consume a Scoped service directly.
// Fix: Inject IServiceScopeFactory and create scopes on demand.
builder.Services.AddScoped<IUserService, UserService>();
builder.Services.AddSingleton<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IServiceScopeFactory>()));

// BREAKING CHANGE (.NET 9): HttpClientFactory now uses SocketsHttpHandler as
// the default primary handler. Casting to HttpClientHandler throws
// InvalidCastException.
// Fix: Use ConfigurePrimaryHttpMessageHandler with the desired handler type.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });

// BREAKING CHANGE (.NET 9): ForwardedHeadersMiddleware now ignores
// X-Forwarded-* headers from proxies not in KnownProxies/KnownNetworks.
// Fix: Register your trusted reverse-proxy addresses.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(IPAddress.Parse("127.0.0.1")); // TODO: replace with actual proxy IP
});

// BREAKING CHANGE (.NET 9): Trace-level HttpClientFactory logs now redact all
// header values by default, breaking header-debugging workflows.
// Fix: Allowlist specific non-sensitive headers you need to inspect.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        h != "X-Request-Id"
        && h != "X-Correlation-Id"
        && h != "Content-Type"
        && h != "Accept"));

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

